UPDATE object_outbox
SET status = 'published',
    published_at = #{publishedAt},
    last_error = '',
    updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE object_outbox
SET status = 'dlq',
    retry_count = #{retryCount},
    last_error = #{lastError},
    updated_at = #{updatedAt}
WHERE id = #{id}
